/// `coroutine.yield([...])` — suspend the running coroutine.
///
/// All arguments are passed back as results of the corresponding `resume`.
///
/// C: `static int luaB_yield(lua_State *L)`
///
/// Phase A–D buffering emulation: if a `coroutine.wrap` body is running
/// (signalled by a yield buffer on top of the LuaState buffer stack), the
/// arguments are appended into that buffer and yield returns 0 values
/// without suspending — the wrapped function continues to run synchronously
/// and the wrap closure dispenses the buffered values one per call. If no
/// buffer is active (a true `coroutine.create` resume), this falls back to
/// the Phase E stub error. Phase E replaces the whole emulation with real
/// stackful coroutines via corosensei.
pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
    if state.has_yield_buffer() {
        let nargs = state.get_top();
        for i in 1..=nargs {
            let v = state.value_at(i);
            state.yield_buffer_push(v);
        }
        return Ok(0);
    }
    let _nargs = state.get_top();
    Err(LuaError::runtime(format_args!(
        "not yet implemented: coroutine.yield (Phase E)"
    )))
}

